```javascript
import { withDb } from "./db.mjs";

const SIGNAL_ORDER = [
  "Regulatory hold",
  "Overdue invoice",
  "Delayed shipment",
  "Escalated support",
  "Usage decline",
];

const SIGNAL_TO_OWNER = [
  ["Regulatory hold", "Legal"],
  ["Overdue invoice", "Finance"],
  ["Delayed shipment", "Customer Success"],
  ["Usage decline", "Customer Success"],
  ["Escalated support", "Support"],
];

const OWNER_ORDER = ["Legal", "Finance", "Customer Success", "Support"];

function deriveSignals(doc, nowIso) {
  const now = new Date(nowIso);
  const active = new Set();

  if (doc.regulatoryFlags?.some(f => f.status === "open")) {
    active.add("Regulatory hold");
  }

  if (doc.invoices?.some(inv => {
    const unpaid = inv.status === "unpaid" || inv.status === "overdue";
    const pastDue = new Date(inv.dueDate) < now;
    const bigEnough = inv.amountCents >= 2500000;
    return unpaid && pastDue && bigEnough;
  })) {
    active.add("Overdue invoice");
  }

  if (doc.shipments?.some(s => !s.deliveredDate && new Date(s.slaDate) < now)) {
    active.add("Delayed shipment");
  }

  if (doc.supportCases?.some(c => c.status === "open" && (c.severity === "high" || c.severity === "critical"))) {
    active.add("Escalated support");
  }

  if (doc.usage) {
    const { currentPeriodUnits, priorPeriodUnits } = doc.usage;
    if (currentPeriodUnits <= priorPeriodUnits * 0.7) {
      active.add("Usage decline");
    }
  }

  return SIGNAL_ORDER.filter(s => active.has(s));
}

function deriveOwners(signals) {
  const ownerSet = new Set();
  for (const [signal, owner] of SIGNAL_TO_OWNER) {
    if (signals.includes(signal)) ownerSet.add(owner);
  }
  return OWNER_ORDER.filter(o => ownerSet.has(o));
}

export async function run(now = "2026-06-18T12:00:00.000Z") {
  await withDb(async (client) => {
    const { rows: accounts } = await client.query("SELECT account_id, doc FROM accounts");

    for (const { account_id, doc } of accounts) {
      const requestId = doc.request?.requestId ?? `req-${account_id}`;
      const tier = doc.tier;
      const qualifyingTiers = ["strategic", "enterprise"];

      const signals = deriveSignals(doc, now);
      const qualifies = qualifyingTiers.includes(tier) && signals.length > 0;

      const status = qualifies
        ? "At-risk escalation active with executive recovery owner routing and customer-visible audit history."
        : "Monitoring — no escalation required.";

      const owners = qualifies ? deriveOwners(signals) : [];
      const topOwner = owners[0] ?? null;

      const riskSummary = signals.length > 0
        ? `${signals.length} signals: ${signals.join(", ")}`
        : "0 signals";

      const nextStep = qualifies
        ? `${topOwner} recovery review by 16:00`
        : "Continue standard monitoring.";

      await client.query(
        `INSERT INTO workflow_state (request_id, account_id, title, status, next_step, risk_summary)
         VALUES ($1, $2, $3, $4, $5, $6)`,
        [requestId, account_id, doc.request?.title ?? "Strategic account rescue", status, nextStep, riskSummary]
      );

      if (qualifies) {
        const nowDate = new Date(now);
        const dueAt = new Date(Date.UTC(nowDate.getUTCFullYear(), nowDate.getUTCMonth(), nowDate.getUTCDate(), 16, 0, 0, 0));

        for (const owner of owners) {
          await client.query(
            `INSERT INTO owner_tasks (request_id, account_id, owner_group, title, due_at, status)
             VALUES ($1, $2, $3, $4, $5, $6)`,
            [
              requestId,
              account_id,
              owner,
              `${owner} recovery action for ${doc.name ?? account_id}`,
              dueAt.toISOString(),
              "open",
            ]
          );
        }

        const body = `Dear ${doc.name ?? "Valued Customer"}, we have identified ${signals.length} active concern${signals.length !== 1 ? "s" : ""} affecting your account (${signals.join(", ")}) and have engaged our ${owners.join(", ")} teams to work with you toward resolution. Your dedicated recovery team will be in contact shortly to coordinate next steps and ensure a positive outcome.`;

        await client.query(
          `INSERT INTO customer_messages (request_id, account_id, body) VALUES ($1, $2, $3)`,
          [requestId, account_id, body]
        );

        await client.query(
          `INSERT INTO audit_events (request_id, account_id, event, occurred_at, customer_visible)
           VALUES ($1, $2, $3, $4, $5)`,
          [
            requestId,
            account_id,
            `Escalation initiated: ${riskSummary}. Recovery owners assigned: ${owners.join(", ")}.`,
            now,
            true,
          ]
        );
      }
    }
  });
}

if (import.meta.url === `file://${process.argv[1]}`) {
  run().then(() => console.log("workflow done")).catch((e) => { console.error(e); process.exit(1); });
}
